你是一个实施子 agent。请执行以下任务。

## 背景
项目：D:\frontend\hse-contractor
`src/service/apis/contractorPortal.ts` 目前同时使用两个 HTTP 客户端：
- `http`（from `@common/service/request`）用于公开接口
- `contractorHttp`（from `@/service/contractorRequest`）用于需要 EToken 的接口

现在 common `http` 已经统一支持 EToken，不再需要 `contractorHttp`，全部改用 `http`。

## 任务
用以下完整内容覆盖写入 `src/service/apis/contractorPortal.ts`：

```typescript
import http from '@common/service/request'
import type { LoginResponseParam, LoginRequestParam } from '@common/types/login'

export async function getContractorDetail(data) {
  return http.request<object>({
    url: '/openapi/permit/contractor/detail',
    method: 'post',
    data,
  })
}

export async function contractorSubmit(data) {
  return http.request<object>({
    url: '/openapi/permit/contractor/submit',
    method: 'post',
    data,
  })
}

export async function getContractorApprovedDetail(data) {
  return http.request<object>({
    url: '/openapi/permit/contractor/approved-detail',
    method: 'post',
    data,
  })
}

export async function openapiUploadFile(data, token) {
  return http.request<object>({
    url: `/openapi/permit/contractor/upload?type=${data.get('type')}&token=${token}`,
    method: 'post',
    data,
    headers: {
      'Content-Type': 'multipart/form-data',
    },
  })
}

export async function contractorLogin(data: LoginRequestParam) {
  return http.request<LoginResponseParam>({
    url: `/openapi/contractor/login`,
    method: 'post',
    data,
    headers: {
      hideToast: true,
    },
  })
}

export async function contractorLogout(data) {
  return http.request<object>({
    url: '/openapi/contractor/logout',
    method: 'post',
    data,
  })
}

export async function sendResetPasswordEmail(data) {
  return http.request<object>({
    url: '/openapi/contractor/sendResetPasswordEmail',
    method: 'post',
    data,
    headers: { hideToast: true },
  })
}

export async function contractorResetPassword(data) {
  return http.request<object>({
    url: '/openapi/contractor/setPasswordByEmail',
    method: 'post',
    data,
  })
}

export async function getPatrolList(data) {
  return http.request<object>({
    url: '/openapi/patrol/page',
    method: 'post',
    data,
  })
}

export async function savePatrol(data) {
  return http.request<object>({
    url: '/openapi/patrol/save',
    method: 'post',
    data,
  })
}

export async function patrolFindingCount(data) {
  return http.request<object>({
    url: '/openapi/patrol/finding/count',
    method: 'post',
    data,
  })
}

export async function getPatrolDetail(data) {
  return http.request<object>({
    url: '/openapi/patrol/detail',
    method: 'post',
    data,
  })
}

export async function savePatrolForm(data) {
  return http.request<object>({
    url: '/openapi/patrol/form/save',
    method: 'post',
    data,
  })
}

export async function submitPatrolForm(data) {
  return http.request<object>({
    url: '/openapi/patrol/submit',
    method: 'post',
    data,
  })
}

export async function getPatrolApprovalRecord(data) {
  return http.request<object>({
    url: '/openapi/patrol/approve/detail',
    method: 'post',
    data,
  })
}

export async function getPatrolOrgTreeRecursion() {
  return http.request<object>({
    url: '/openapi/org/tree',
    method: 'post',
  })
}

export async function deletePatrol(data: { patrolId: number }) {
  return http.request<object>({
    url: '/openapi/patrol/delete',
    method: 'post',
    data,
  })
}

export async function patrolUploadFile(data) {
  return http.request<object>({
    url: `/openapi/patrol/upload?type=${data.get('type')}`,
    method: 'post',
    data,
    headers: {
      'Content-Type': 'multipart/form-data',
    },
  })
}
```

## 步骤
1. 读取当前文件确认
2. 写入新内容
3. 提交：`git add src/service/apis/contractorPortal.ts && git commit -m "chore: replace contractorHttp with http in contractorPortal APIs"`

## 报告
DONE / BLOCKED + 说明

